(ns apex-chart.core
  (:require [reagent.core :as r]
            [reagent.dom :as rdom]))

(defn get-time [date-string]
  (.-getTime (js/Date. date-string)))

(defn apex-chart []
  (let [state (r/atom {:series [{:name "Bob"
                                  :data [{:x "Design" :y [(get-time "2019-03-05") (get-time "2019-03-08")]}
                                         {:x "Code" :y [(get-time "2019-03-02") (get-time "2019-03-05")]}
                                         {:x "Code" :y [(get-time "2019-03-05") (get-time "2019-03-07")]}
                                         {:x "Test" :y [(get-time "2019-03-03") (get-time "2019-03-09")]}
                                         {:x "Test" :y [(get-time "2019-03-08") (get-time "2019-03-11")]}
                                         {:x "Validation" :y [(get-time "2019-03-11") (get-time "2019-03-16")]}
                                         {:x "Design" :y [(get-time "2019-03-01") (get-time "2019-03-03")]}]}
                                {:name "Joe"
                                 :data [{:x "Design" :y [(get-time "2019-03-02") (get-time "2019-03-05")]}
                                        {:x "Test" :y [(get-time "2019-03-06") (get-time "2019-03-16")]
                                         :goals [{:name "Break" :value (get-time "2019-03-10") :strokeColor "#CD2F2A"}]}
                                        {:x "Code" :y [(get-time "2019-03-03") (get-time "2019-03-07")]}
                                        {:x "Deployment" :y [(get-time "2019-03-20") (get-time "2019-03-22")]}
                                        {:x "Design" :y [(get-time "2019-03-10") (get-time "2019-03-16")]}]}
                                {:name "Dan"
                                 :data [{:x "Code" :y [(get-time "2019-03-10") (get-time "2019-03-17")]}
                                        {:x "Validation" :y [(get-time "2019-03-05") (get-time "2019-03-09")]
                                         :goals [{:name "Break" :value (get-time "2019-03-07") :strokeColor "#CD2F2A"}]}]}]
                     :options {:chart {:height 450 :type "rangeBar"}
                               :plotOptions {:bar {:horizontal true :barHeight "80%"}}
                               :xaxis {:type "datetime"}
                               :stroke {:width 1}
                               :fill {:type "solid" :opacity 0.6}
                               :legend {:position "top" :horizontalAlign "left"}}})]
    (fn []
      [:div
        [:div#chart
         [react-apex-chart (:options @state) (:series @state) "rangeBar" 450]]
        [:div#html-dist]])))

(defn mount-apex-chart []
  (rdom/render [apex-chart] (.querySelector js/document "#app")))

(defn ^:export main []
  (mount-apex-chart))
